class Solution:
    def findRightInterval(self, intervals) -> list:
        import bisect
        start_map = {s: i for i, (s, e) in enumerate(intervals)}
        sorted_starts = sorted(start_map.keys())
        result = []
        for s, e in intervals:
            idx = bisect.bisect_left(sorted_starts, e)
            if idx < len(sorted_starts):
                result.append(start_map[sorted_starts[idx]])
            else:
                result.append(-1)
        return result

