var findRightInterval = function(intervals) {
    const n = intervals.length;
    const startMap = new Map();
    for (let i = 0; i < n; i++) startMap.set(intervals[i][0], i);
    const sortedStarts = [...startMap.keys()].sort((a, b) => a - b);
    const bisectLeft = (arr, target) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    };
    return intervals.map(([s, e]) => {
        const idx = bisectLeft(sortedStarts, e);
        return idx < sortedStarts.length ? startMap.get(sortedStarts[idx]) : -1;
    });
};
